channels = get_channels()

# Collect all channel messages
all_messages = []
all_messages = [msg for channel in channels for msg in read_channel_messages(channel)]

# Count messages per sender
counts = {}
for msg in all_messages:
    counts = {**counts, msg.sender: counts.get(msg.sender, 0) + 1}

# Get all users - use users from channels to include everyone
users_set = set()
for channel in channels:
    users_in_ch = get_users_in_channel(channel)
    users_set = users_set | set(users_in_ch)

# Ensure all users have a count (default 0)
for user in users_set:
    if user not in counts:
        counts = {**counts, user: 0}

# Sort: by count descending, then alphabetically ascending
sorted_users = sorted(counts.items(), key=lambda x: (-x[1], x[0]))

# Send messages
for rank, (user, cnt) in enumerate(sorted_users, start=1):
    send_direct_message(user, f"Congrats on being the {rank}-th most active user!")
    print(f"Sent to {user} (rank {rank}, {cnt} messages)")
